import React from "react";
import styles from "./table-heading.module.css";
import GridLayout from "../../layout/grid-layout";

const TableHeading = () => {
  return (
    <div className={styles.wrapper_table}>
      <div className={styles.container_inner}>
        <div className={styles.left_side}>
          <h6 className={styles.table_title}>Product</h6>d
        </div>
        <div className={styles.right_side}>
          <h6 className={styles.table_title}>Price</h6>
          <h6 className={styles.table_title}>Quantity</h6>
          <h6 className={styles.table_title}>Total</h6>
        </div>
      </div>

      <div className={styles.divider} />
    </div>
  );
};

export default TableHeading;
